import React from "react";
import { Link } from "react-scroll";
import logo from "../assets/logo.png"; 
import "../styles.css"; // Import styles

const Navbar = () => {
  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <img src="/logo.png"  />
      </div>
      <ul className="navbar-links">
        {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "COUNTACT US"].map((section) => (
          <li key={section}>
            <Link 
              to={section} 
              smooth={true} 
              duration={500} 
              activeClass="active"  // Active class for selected section
            >
              {section.replace(/^\w/, (c) => c.toUpperCase()).replace("-", " ")}
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
